import { mkdir, readFile, rename, writeFile } from "node:fs/promises";
import { dirname } from "node:path";

export type Phase = "detected" | "begun" | "withdrawn" | "swap-submitted" | "swapped" | "pool-submitted" | "pooled" | "finalized" | "failed";
export type MigrationRecord = {
  curve: string;
  mint: string;
  phase: Phase;
  withdrawnSol?: string;
  withdrawnTokens?: string;
  swapInput?: string;
  preSwapCoreBalance?: string;
  quotedCoreAmount?: string;
  signedSwapTransaction?: string;
  jupiterRequestId?: string;
  lastValidBlockHeight?: string;
  coreReceived?: string;
  swapSignature?: string;
  poolId?: string;
  poolSignature?: string;
  burnSignature?: string;
  error?: string;
  updatedAt: string;
};

type Store = Record<string, MigrationRecord>;

export class StateStore {
  private data: Store = {};
  constructor(private readonly path: string) {}

  async load(): Promise<void> {
    try { this.data = JSON.parse(await readFile(this.path, "utf8")); }
    catch (error: any) { if (error?.code !== "ENOENT") throw error; }
  }

  get(curve: string): MigrationRecord | undefined { return this.data[curve]; }

  async patch(curve: string, patch: Partial<MigrationRecord>): Promise<MigrationRecord> {
    const previous = this.data[curve] ?? { curve, mint: "", phase: "detected", updatedAt: new Date().toISOString() };
    const next = { ...previous, ...patch, updatedAt: new Date().toISOString() } as MigrationRecord;
    this.data[curve] = next;
    await this.flush();
    return next;
  }

  private async flush(): Promise<void> {
    await mkdir(dirname(this.path), { recursive: true });
    const temp = `${this.path}.tmp`;
    await writeFile(temp, JSON.stringify(this.data, null, 2));
    await rename(temp, this.path);
  }
}

import * as anchor from "@coral-xyz/anchor";
import { Program } from "@coral-xyz/anchor";
import {
  createInitializeMintInstruction,
  getAssociatedTokenAddressSync,
  getMinimumBalanceForRentExemptMint,
  MINT_SIZE,
  TOKEN_PROGRAM_ID,
  ASSOCIATED_TOKEN_PROGRAM_ID,
} from "@solana/spl-token";
import { Keypair, LAMPORTS_PER_SOL, PublicKey, SystemProgram, Transaction } from "@solana/web3.js";
import idl from "../target/idl/core_launchpad.json" with { type: "json" };

const provider = anchor.AnchorProvider.env();
anchor.setProvider(provider);
const program = new Program(idl as anchor.Idl, provider);

const globalPda = PublicKey.findProgramAddressSync([Buffer.from("global")], program.programId)[0];

describe("core-launchpad", () => {
  it("initializes config, creates a fixed-supply launch, and buys", async () => {
    const admin = provider.wallet.publicKey;
    try {
      await program.methods.initializeConfig(
        admin,
        admin,
        Keypair.generate().publicKey,
        new anchor.BN(LAMPORTS_PER_SOL),
        100,
      ).accounts({ admin, global: globalPda, systemProgram: SystemProgram.programId }).rpc();
    } catch (error: any) {
      if (!String(error).includes("already in use")) throw error;
    }

    const mint = Keypair.generate();
    const rent = await getMinimumBalanceForRentExemptMint(provider.connection);
    const createMintTx = new Transaction().add(
      SystemProgram.createAccount({ fromPubkey: admin, newAccountPubkey: mint.publicKey, lamports: rent, space: MINT_SIZE, programId: TOKEN_PROGRAM_ID }),
      createInitializeMintInstruction(mint.publicKey, 6, admin, null),
    );
    await provider.sendAndConfirm(createMintTx, [mint]);

    const curve = PublicKey.findProgramAddressSync([Buffer.from("curve"), mint.publicKey.toBuffer()], program.programId)[0];
    const tokenVault = getAssociatedTokenAddressSync(mint.publicKey, curve, true);
    await program.methods.createLaunch(
      "Test Core", "TCORE", "https://example.com/metadata.json",
      new anchor.BN("1000000000000000"),
      new anchor.BN("793100000000000"),
      new anchor.BN("206900000000000"),
      new anchor.BN("30000000000"),
      new anchor.BN("1031030000000000"),
    ).accounts({
      global: globalPda, creator: admin, mint: mint.publicKey, curve, tokenVault,
      tokenProgram: TOKEN_PROGRAM_ID, associatedTokenProgram: ASSOCIATED_TOKEN_PROGRAM_ID,
      systemProgram: SystemProgram.programId,
    }).rpc();

    const buyerTokenAccount = getAssociatedTokenAddressSync(mint.publicKey, admin);
    await program.methods.buy(new anchor.BN(100_000_000), new anchor.BN(1)).accounts({
      global: globalPda, curve, mint: mint.publicKey, tokenVault, buyer: admin,
      buyerTokenAccount, feeReceiver: admin, tokenProgram: TOKEN_PROGRAM_ID,
      associatedTokenProgram: ASSOCIATED_TOKEN_PROGRAM_ID, systemProgram: SystemProgram.programId,
    }).rpc();

    let state: any = await (program.account as any).curve.fetch(curve);
    if (state.realSolReserves.lte(new anchor.BN(0))) throw new Error("SOL reserve did not increase");
    if (state.realTokenReserves.gte(new anchor.BN("793100000000000"))) throw new Error("Token reserve did not decrease");

    // The program treats the submitted amount as a maximum and collects only
    // enough to land exactly on the snapshotted 1 SOL test threshold.
    await program.methods.buy(new anchor.BN(2 * LAMPORTS_PER_SOL), new anchor.BN(1)).accounts({
      global: globalPda, curve, mint: mint.publicKey, to

kenVault, buyer: admin,
      buyerTokenAccount, feeReceiver: admin, tokenProgram: TOKEN_PROGRAM_ID,
      associatedTokenProgram: ASSOCIATED_TOKEN_PROGRAM_ID, systemProgram: SystemProgram.programId,
    }).rpc();
    state = await (program.account as any).curve.fetch(curve);
    if (!state.realSolReserves.eq(new anchor.BN(LAMPORTS_PER_SOL))) throw new Error("Graduation did not cap at exactly 1 SOL");
    if (state.status !== 1) throw new Error("Curve did not enter MigrationReady");

    let tradingClosed = false;
    try {
      await program.methods.buy(new anchor.BN(1_000_000), new anchor.BN(1)).accounts({
        global: globalPda, curve, mint: mint.publicKey, tokenVault, buyer: admin,
        buyerTokenAccount, feeReceiver: admin, tokenProgram: TOKEN_PROGRAM_ID,
        associatedTokenProgram: ASSOCIATED_TOKEN_PROGRAM_ID, systemProgram: SystemProgram.programId,
      }).rpc();
    } catch {
      tradingClosed = true;
    }
    if (!tradingClosed) throw new Error("Trading remained open after graduation");
  });
});

import { generateVanityMint } from "@nirholas/pump-sdk";

const suffix = process.argv[2] ?? "pump";
console.log(`Grinding a mint ending in ${suffix}. This is optional and runs off-chain.`);
const result = await generateVanityMint({
  suffix,
  onProgress: (attempts) => {
    if (attempts % 1_000_000 === 0) console.log(`${attempts.toLocaleString()} attempts`);
  },
});
console.log("mint:", result.keypair.publicKey.toBase58());
console.log("secretKey:", JSON.stringify(Array.from(result.keypair.secretKey)));
